function StructGuildInfo:CreateByPb(pb,bool)
    self.guildId = pb.guildId
    self.guildName = pb.guildName
    self.level = pb.level
    local notice = pb.notice or ""
    local noticeKey = pb.noticeKey or ""
    local _notice = ""
    if noticeKey ~= "" then
        _notice = ccLngText(noticeKey)
    else
        if(notice ~= "" and not bool)then
            _notice = ccLngText(notice)
            if _notice == "" then
                _notice = LWordMaskUtil.ClearShieldWord(notice)
            end
        else
            _notice = notice
        end
    end
    self.notice = _notice
    local playerInfo=StructPlayerInfo:New()
    playerInfo:CreateByPb(pb.chairman)
    self.chairman=playerInfo
    self.activity=pb.activity
    self.exp=pb.exp
    self.count=pb.count
    self.levelLimit=pb.levelLimit
    self.approve=pb.approve
    local announcementKey = pb.announcementKey or ""
    local announcement = pb.announcement
    local _announcement = ""
    if(announcementKey ~= "")then
        _announcement = ccLngText(announcementKey)
    else
        if(announcement and announcement ~= "" and not bool)then
            _announcement = LWordMaskUtil.ClearShieldWord(announcement)
        else
            _announcement = pb.announcement
        end
    end
    self.announcement = _announcement
    self.activityWeek=pb.activityWeek
    self.mailCount=pb.mailCount
    self.recruitCount=pb.recruitCount
    self.createTime=pb.createTime
    self.power = pb.power
    self.flagId = pb.flagId
    self.flagBgId = pb.flagBgId
    self.serverFlag = pb.serverFlag

    -- 【D多语言】删除多语言联盟机制（客户端&服务端）
